import{j as e,r as h}from"./index-DO1XXD1f.js";const o=({children:s,className:r=""})=>e.jsx("section",{className:"row rowText "+r,children:s}),t=({text:s,images:r,imageRight:i=!1})=>e.jsxs("section",{className:"row rowTextImages "+(i?"imageRight":"imageLeft"),children:[e.jsx("div",{children:s}),e.jsx("div",{children:r.map((a,l)=>e.jsxs("figure",{children:[e.jsx("img",{src:a.src,alt:a.alt,onClick:()=>window.open(a.src,"_blank")}),a.caption&&e.jsx("figcaption",{children:a.caption})]},l))})]}),n=({spacing:s})=>e.jsx("section",{className:"row rowSeparator",style:{margin:s}});function d(){const[s,r]=h.useState(0);h.useEffect(()=>{const a=setInterval(()=>{r(l=>(l+1)%i.length)},2500);return()=>clearInterval(a)},[]);const i=[{src:"/articles/devChronicles/images/brennansMiniGame/5.png",alt:"Screenshot of Brennan's Mini Game"},{src:"/articles/devChronicles/images/theIslandOfFareo/1.png",alt:"Screenshot of The Island of Fareo"},{src:"/articles/devChronicles/images/forlorn/3.png",alt:"Screenshot of Forlorn"},{src:"/articles/devChronicles/images/ultimateArena/1.png",alt:"Screenshot of Ultimate Arena"},{src:"/articles/devChronicles/images/pigRiding2/3.png",alt:"Screenshot of Pig Riding"},{src:"/articles/devChronicles/images/theInternet/1.png",alt:"Screenshot of The Internet"},{src:"/articles/devChronicles/images/galaxySprint/2.png",alt:"Screenshot of Galaxy Sprint"},{src:"/articles/devChronicles/images/darkening/1.png",alt:"Screenshot of Darkening"}];return e.jsxs(e.Fragment,{children:[i.length>0&&e.jsx("div",{id:"header-images",children:i.map(a=>e.jsx("img",{className:s==i.indexOf(a)?"active":"",src:a.src,alt:a.alt},a))}),e.jsx("h1",{id:"title",children:"Game Development Chronicles"}),e.jsxs("main",{children:[e.jsx(n,{spacing:"50px"}),e.jsx("p",{className:"sectionHeading",children:"A Small Disclaimer"}),e.jsx(o,{children:e.jsx("p",{children:"Now I'd like to begin by establishing that this isn't supposed to be any sort of serious article or anything. I just thought it'd be fun to reminisce on some of my old projects and explain a little about each one. On the same note, I also want to denote that I do not consider myself a professional developer by any standard, so if I happen to say things in a way that makes them sound correct and they aren't, that's probably why. I just happen to have interests in development and have been doing it for a long span of time, but I don't have any real, professional experience, so all of this is just stuff I've taught myself along the way."})}),e.jsx(n,{spacing:"50px"}),e.jsx("p",{className:"sectionHeading",children:"Before The Real Stuff"}),e.jsx(o,{children:e.jsxs("p",{children:["My first couple of projects I generally consider to be the beginning of my interests in software and game development, although I wouldn't necessarily call them projects either. That being, these were projects I worked on in the games ",e.jsx("i",{children:"Geometry Dash"})," and ",e.jsx("i",{children:"Minecraft"}),". I imagine those don't sound much like game engines or anything even related to any form of development, but I consider them to be the genesis of my development interests for the fact that they both had their own sort of programming languages within the games themselves."]})}),e.jsx(o,{children:e.jsxs("p",{children:[e.jsx("i",{children:"Geometry Dash"}),`, if you've never played or created levels in it, has it's own sort of "programming language", called triggers. Essentially, these triggers allow level creators to basically "program" actions within their levels, whether it be to move objects, rotate objects, make them fade, change color, and much more. Since I was never very good at actually playing the game, I'd pretty much always be in the editor trying my best to make good levels, although they almost were never finished. Even in the rare case that I did finish one, they were never very good. Despite this, I've always considered `,e.jsx("i",{children:"Geometry Dash"})," to be pretty much the very beginning of my interest. I won't be going over my levels in this article, however, they are all still up on my account, if you'd like to find them."]})}),e.jsx(n,{spacing:"150px"}),e.jsx("p",{className:"sectionHeading",children:"Minecraft Projects"}),e.jsx(o,{children:e.jsxs("p",{children:["Not long after ",e.jsx("i",{children:"Geometry Dash"}),", came my ",e.jsx("i",{children:"Minecraft"})," development phase. ",e.jsx("i",{children:"Minecraft"}),` has a much more customizable "programming language", in the form of commands. Despite most commands seeming pretty simple, such as teleporting, setting the time, spawning mobs, and more, there's actually much more depth that commands can provide given you know how to use them. With more in-depth commands, I tried to create various "games", although I would describe them as something more of minigames. Luckily, I managed to recover some of these projects from my old iPad, so I'll go over them now. These are not in really any sort of order, since I don't remember when I created each one. Although I tried to order them the best I could by generally when I remember making them.`,e.jsx("br",{}),e.jsx("br",{}),"Unfortunately, these are only the major worlds I still had on that iPad, since I believe a ton of worlds were either not owned by me, or deleted at some point to save space. I feel like I even had a working Five Nights at Freddy's world at some point, but I evidently don't have it any more."]})}),e.jsx("p",{className:"subsectionHeading",children:"1 - death run/minigame world"}),e.jsx(t,{text:e.jsxs("p",{children:[`Now I believe this was my first attempt at a world with multiple minigame options (the second attempt being "Brennan's Mini Game"). This world never made it very far, and I'm not actually sure how functional any of it is (clearly not very, considering it `,e.jsx("i",{children:"didn't"}),` work when I tried). The two minigames I started (but never finished from what I can tell), are murder mystery and death run. I think at this point I also didn't know to how make minigames which had randomness to them, because me and my friends had to basically "register" ourselves to play rounds of the minigames. This also means that if anyone else wanted to play them, they just couldn't. That aside, you'll see in many of these worlds, that the command block and redstone spaghetti looking wires are actually quite cool looking. I haven't looked it over, so I can probably guess that much of it is overcomplicated and unorganized, but cool nonetheless.`]}),images:[{src:"/articles/devChronicles/images/deathRunMinigameWorld/1.png",alt:"Screenshot 1 of death run/minigame world",caption:"Command block work for the death run minigame"},{src:"/articles/devChronicles/images/deathRunMinigameWorld/2.png",alt:"Screenshot 2 of death run/minigame world",caption:"Lobby area of the death run minigame"},{src:"/articles/devChronicles/images/deathRunMinigameWorld/3.png",alt:"Screenshot 3 of death run/minigame world",caption:"An item sorter for murderer and sheriff selection in murder mystery"},{src:"/articles/devChronicles/images/deathRunMinigameWorld/6.png",alt:"Screenshot 4 of death run/minigame world",caption:"Lobby of the murder mystery minigame"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"2 - Break In!"}),e.jsx(t,{text:e.jsx("p",{children:`As far as I remember, this map was more of an attempt at a real, professional minigame rather than the usual casual and messy minigames I was mostly making. The premise of the minigame was that you'd start outside of a house, with 10 minutes to steal as many valuables from it as possible, and escape. In the house would be the "homeowner", who was just a zombie as far as I can tell, who you'd have to avoid since you couldn't really defend yourself. Then the valuables you'd collect would just be buttons next to things like paintings and armor stands, and they'd disappear when you'd click the button. The game doesn't work anymore (at least on the ported version on my PC), since the structure blocks are set to load from memory and not from disk, so I couldn't really play this one. However, out of all these worlds, this one was probably the closest to a complete and possibly fairly enjoyable one.`}),images:[{src:"/articles/devChronicles/images/breakIn/4.png",alt:"Screenshot 1 of Break In!",caption:"Lobby area"},{src:"/articles/devChronicles/images/breakIn/3.png",alt:"Screenshot 2 of Break In!",caption:"Outside of the house map"},{src:"/articles/devChronicles/images/breakIn/2.png",alt:"Screenshot 3 of Break In!",caption:"Command blocks controlling start and end of the round"},{src:"/articles/devChronicles/images/breakIn/1.png",alt:"Screenshot 4 of Break In!",caption:"Section of the inside of the house map"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"3 - U r Super"}),e.jsx(t,{text:e.jsx("p",{children:"I'd like to first state that I have no idea why I called it that back then, because that's the literal name of the world. Other than that, I actually have really nothing to say about this world. The premise of this one was that it was a sort of wave based survival game, where you'd choose a class before the game starts, and fight through waves of enemies while getting upgrades. Which actually makes me realize only now that I basically created a rougelike game without even knowing at the time what that was. Other than the idea being cool, the execution of it never made it far and it's beyond broken now, with again the issue being that the structure blocks don't work anymore (and some of the command blocks don't seem to be working either?). Despite having nothing notable to say about this one, it actually is the world with the best memories I have from this time period."}),images:[{src:"/articles/devChronicles/images/urSuper/1.png",alt:"Screenshot 1 of U r Super",caption:"Main arena map"},{src:"/articles/devChronicles/images/urSuper/2.png",alt:"Screenshot 2 of U s Super",caption:"Class selection area"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"4 - Ultimate Arena"}),e.jsx(t,{text:e.jsxs("p",{children:[`Now this world was actually meant to be a sort of successor to "U r Super", with improved maps, class unlocking, and more. Once again, never made it far, but it has one of the coolest (in my option at least), systems I ever made with command blocks. As shown in the pictures, it features a loot box type of system for unlocking new classes, and although actual classes were never added or anything, the logic for the loot boxes is so cool to me. Basically, Minecraft doesn't have a command for generating random values (at least to my knowledge), and so I had to come up with a system which would pick random numbers, but also have weight to them for rarities. This resulted in me using the teleport command to teleport an entity to a random armor stand in a certain radius, with more armor stands for one rarity representing higher odds. It probably doesn't sound like the most complicated thing there is, but to me back then, it was so impressive.`,e.jsx("br",{}),e.jsx("br",{}),`Like I said, this one never made it very far, in fact, it barely made it anywhere at all. That loot box system was pretty much all it had for it. One of my friends started an "Atlantis" map, which was never fully finished, and the actual gameplay I don't think was ever even started.`]}),images:[{src:"/articles/devChronicles/images/ultimateArena/4.png",alt:"Screenshot 1 of Ultimate Arena",caption:"Aforementioned random number and rarity armor stand system"},{src:"/articles/devChronicles/images/ultimateArena/1.png",alt:"Screenshot 2 of Ultimate Arena",caption:"Command block and hopper system for delivering class unlocks to the current loot box"},{src:"/articles/devChronicles/images/ultimateArena/3.png",alt:"Screenshot 3 of Ultimate Arena",caption:"Loot box unlocking room"},{src:"/articles/devChronicles/images/ultimateArena/2.png",alt:"Screenshot 4 of Ultimate Arena",caption:"Command block mess for the loot box unlocking"},{src:"/articles/devChronicles/images/ultimateArena/5.png",alt:"Screenshot 5 of Ultimate Arena",caption:"The unfinished Atlantis map"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"5 - ____ & Brenman60's Towers"}),e.jsx(t,{text:e.jsxs("p",{children:[`I'm actually not sure what the point of this world was, but if you've ever played those Roblox tower games, that's basically just what this is. It's a set of parkour towers me and a friend made (I replaced their username with underscores in the title as to not call them out...), and as you might have guessed, never finished. If you have no idea what that is, it's essentially towers filled with parkour that if you fall down, you have to restart the whole thing. In terms of completeness, this world is actually somewhat complete, since there's about 3 towers that are fully built. Although I suppose "completeness" varies in this case.`,e.jsx("br",{}),e.jsx("br",{}),"There's nothing really notable to say about this world, so let's just move on."]}),images:[{src:"/articles/devChronicles/images/brenman60Towers/1.png",alt:"Screenshot 1 of ____ & Brenman60's Towers",caption:"Tower selection lobby"},{src:"/articles/devChronicles/images/brenman60Towers/2.png",alt:"Screenshot 2 of ____ & Brenman60's Towers",caption:"Tutorial"},{src:"/articles/devChronicles/images/brenman60Towers/3.png",alt:"Screenshot 3 of ____ & Brenman60's Towers",caption:"The Color Tower"},{src:"/articles/devChronicles/images/brenman60Towers/4.png",alt:"Screenshot 4 of ____ & Brenman60's Towers",caption:"The Tower of Hell"},{src:"/articles/devChronicles/images/brenman60Towers/5.png",alt:"Screenshot 5 of ____ & Brenman60's Towers",caption:"Some command blocks for general functionality"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"6 - Brennan's Mini Game"}),e.jsx(t,{text:e.jsxs("p",{children:["This was probably one of the longest running and most advanced minigame worlds I worked on. It features murder mystery, death run, and escape rooms, with other minigames planned but never actually created.",e.jsx("br",{}),e.jsx("br",{}),`Murder mystery unfortunately fails once again at being applicable to any set of players, since it requires the host to "register" the players (me and my friends) in order to play, just like how it worked in "death run/minigame world". I can't get it working anymore and I don't have any players to test it with anyway, but I do remember this version of murder mystery at least being quite fun compared to the last.`,e.jsx("br",{}),e.jsx("br",{}),"The TNT run works about as you'd expect, but has some fun quirks to it that makes it a little unique compared to most. Namely, it has modifiers you can edit before the beginning of a game, which effect how you'll play. The modifiers I added were potion effects and mobs that spawn during the round. They don't change the game a ton but are fun to play around with.",e.jsx("br",{}),e.jsx("br",{}),"Finally, the escape rooms were probably the most technically impressive and largest minigames I created. There's only one, not finished of course, and looking back on, very embarrassing. The actual escape room itself is quite buggy so it was hard to get it working properly, but the biggest grievance I found was the story I tried writing. I don't know how great a story I could write for something like this could be even now, so back then I had no idea what I was doing, which resulted in some really awkward writing. As well as that, I Also Used To Write Like This With Every Word Capitalized For Some Reason???"]}),images:[{src:"/articles/devChronicles/images/brennansMiniGame/1.png",alt:"Screenshot 1 of Brennan's Mini Game",caption:"Main lobby for choosing minigames"},{src:"/articles/devChronicles/images/brennansMiniGame/2.png",alt:"Screenshot 2 of Brennan's Mini Game",caption:"TNT run minigame"},{src:"/articles/devChronicles/images/brennansMiniGame/3.png",alt:"Screenshot 3 of Brennan's Mini Game",caption:"Puzzle room of escape room"},{src:"/articles/devChronicles/images/brennansMiniGame/4.png",alt:"Screenshot 4 of Brennan's Mini Game",caption:"Redstone and command blocks for escape room"},{src:"/articles/devChronicles/images/brennansMiniGame/5.png",alt:"Screenshot 5 of Brennan's Mini Game",caption:"Redstone and command blocks for murder mystery"},{src:"/articles/devChronicles/images/brennansMiniGame/6.png",alt:"Screenshot 6 of Brennan's Mini Game",caption:"Maps for murder mystery"},{src:"/articles/devChronicles/images/brennansMiniGame/7.png",alt:"Screenshot 7 of Brennan's Mini Game",caption:"Lobby for murder mystery"},{src:"/articles/devChronicles/images/brennansMiniGame/8.png",alt:"Screenshot 8 of Brennan's Mini Game",caption:"Redstone and command blocks for TNT run"}],imageRight:!0}),e.jsx(n,{spacing:"150px"}),e.jsx("p",{className:"sectionHeading",children:"The Roblox Saga"}),e.jsx(o,{children:e.jsx("p",{children:"Sometime around the beginning of the Covid Pandemic, only 6th grade in middle school for me (I know), I began learning Roblox development. I'm actually not really sure why. I'd imagine it was probably a mixture of the restrictions of Minecraft's commands along with general boredom from being stuck inside all day with nothing else to do. Luckily, I have access to every project I've ever worked on in Roblox, so I'll be going over each significant one."})}),e.jsx(o,{children:e.jsxs("p",{children:["But first, a quick introduction to Roblox game development for anyone unaware. For one, Roblox isn't anything like Unity when it comes to independence. If you're developing a game on Roblox, you can't go anywhere else with it, you end up stuck on Roblox. However, this doesn't stop Roblox from feeling like a traditional game engine in the sense that you're pretty much capable of creating whatever game you want. Apart from the platform restriction, it's actually pretty versatile (Well, 2D games are a different story...).",e.jsx("br",{}),e.jsx("br",{}),"Roblox Studio uses a modified version of the Lua language, named Luau, to have developers program their games. After getting into many forms of development over the years, I find this choice to be really weird. I think Lua is definitely an interesting language, but I've never seen it used before apart from in Roblox. I imagine that Lua was chosen for it's simple learning curve, which is good for Roblox, considering the target audience is young children. You wouldn't really expect a young child to be able to learn any of the popular game development languages, so it makes sense for that purpose. But then again, couldn't they implement multiple languages into the engine, similar to how something like the Godot game engine works?",e.jsx("br",{}),e.jsx("br",{}),"Anyways, enough of that. Let's just get into the projects."]})}),e.jsx(n,{spacing:"50px"}),e.jsx("p",{className:"subsectionHeading",children:"Prologue"}),e.jsx(o,{children:e.jsxs("p",{children:["Alright, so first off, I'd like to establish that there's two primary groups under which I worked on Roblox games (as well as my account itself). The first group I created was with a friend of mine which we called ",e.jsx("a",{href:"https://www.roblox.com/share/g/4424611",target:"_blank",children:"T u r t l e P l a z a"}),". It was created approximately ~2 years (2018) before I properly started learning Roblox development. As a result, I tried and failed to create anything actually good, and eventually we called it quits. Then, two years later (2020), during the time when I was actually learning Roblox game development, we returned to this group, and made a few projects. Some time that same year, my friend and I had gradually drifted apart, and stopped making games on that group all together. Upon receiving approval from myself, they gave the group up to a newly created alt account, deleted as much from the group as they could, and eventually the information to that alt account was lost.",e.jsx("br",{}),e.jsx("br",{}),"Some years later, I was thinking about the projects which I worked on in that group, and had hoped to recover them. I asked that friend if they had saved the password or email to the alt account anywhere, which they had not. As a last resort, I emailed Roblox support practically begging for the group back, and to my shock; they asked for no proof of ownership or anything and simply handed the account over.",e.jsx("br",{}),e.jsx("br",{}),"Because of that, the first few projects shown here are going to be those which I found still under that group."]})}),e.jsx(n,{spacing:"50px"}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 1 - ",e.jsx("a",{href:"https://www.roblox.com/games/5057610967/Sitting-Simulator",target:"_blank",children:"Sitting Simulator"})]}),e.jsx(t,{text:e.jsxs("p",{children:["I actually don't really know where the idea for this game came about, I think it was a joke my friend and I came up with based on the over  abundance of simulator games that plagued Roblox at the time, but that's as far as I remember.",e.jsx("br",{}),e.jsx("br",{}),"As for the game itself, there's really nothing in it. It's just as the title suggests, a simulator where you sit, and nothing else. And as for technicality, it was created during the very very beginning of when I started learning Roblox development, so the code is not very impressive at all. As far as I can tell that timer is also pointless. It does nothing when it hits 0. Which is admittedly pretty funny."]}),images:[{src:"/articles/devChronicles/images/sittingSimulator/1.png",alt:"Screenshot 1 of Sitting Simulator",caption:"Base map with timer"},{src:"/articles/devChronicles/images/sittingSimulator/2.png",alt:"Screenshot 2 of Sitting Simulator",caption:"Multiplayer server with multiple desks and giant furniture hanging"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 2 - ",e.jsx("a",{href:"https://www.roblox.com/games/5081935005/Turtle-Plazas-Parkour-Practice",target:"_blank",children:"Turtle Plaza's Parkour Practice"})]}),e.jsx(t,{text:e.jsxs("p",{children:["From this point onward I worked on these games almost completely alone. As far as I can remember this was the first that I did entirely independently.",e.jsx("br",{}),e.jsx("br",{}),"I think I started this game pretty much because the programming side of it was pretty easy, especially considering I actually don't really like parkour in many games. There's nothing really notable about this game though. It features that Roblox stud texture on every surface and I remember making it a point to have everything symmetrical in terms of those studs, but that's about it."]}),images:[{src:"/articles/devChronicles/images/turtlePlazasParkourPractice/4.png",alt:"Screenshot 1 of Turtle Plaza's Parkour Practice",caption:"Main lobby area, with me holding... my head?"},{src:"/articles/devChronicles/images/turtlePlazasParkourPractice/1.png",alt:"Screenshot 2 of Turtle Plaza's Parkour Practice",caption:"Lines area"},{src:"/articles/devChronicles/images/turtlePlazasParkourPractice/2.png",alt:"Screenshot 3 of Turtle Plaza's Parkour Practice",caption:"Wraps area"},{src:"/articles/devChronicles/images/turtlePlazasParkourPractice/3.png",alt:"Screenshot 4 of Turtle Plaza's Parkour Practice",caption:"Entire map"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 3 - ",e.jsx("a",{href:"https://www.roblox.com/games/5136063715/Scripting-Warehouse",target:"_blank",children:"Scripting Warehouse"})]}),e.jsx(t,{text:e.jsx("p",{children:"I created this game, once again, during the beginning of when I started learning Roblox development. It was meant to display my progress as I learned Luau, but ended pretty prematurely once I no longer cared to update it. Judging by the dates in-game, it seems like I worked on it for about 2 days because moving on. Which honestly was probably the best thing to do. Although it's an interesting idea to have a game like this, it would soon become a pain and more of a chore to display things here instead of just making new projects, so it's no wonder I moved on so quickly."}),images:[{src:"/articles/devChronicles/images/scriptingWarehouse/1.png",alt:"Screenshot 1 of Scripting Warehouse",caption:"Simple about UI"},{src:"/articles/devChronicles/images/scriptingWarehouse/2.png",alt:"Screenshot 2 of Scripting Warehouse",caption:"Light toggle exhibit"},{src:"/articles/devChronicles/images/scriptingWarehouse/3.png",alt:"Screenshot 3 of Scripting Warehouse",caption:"Block spawner exhibit"},{src:"/articles/devChronicles/images/scriptingWarehouse/4.png",alt:"Screenshot 4 of Scripting Warehouse",caption:"Shape changing exhibit"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 4 - ",e.jsx("a",{href:"https://www.roblox.com/games/5366170181/MainServer",target:"_blank",children:"MainServer"})]}),e.jsx(t,{text:e.jsxs("p",{children:["This was a super experimental project and it pretty much never made it past a title screen. One of my favorite games when I was younger was ",e.jsx("i",{children:"Kirby's Return to Dreamland"})," on the Nintendo Wii, and I believe this game was created solely inspired by that. I think I realized I was out of my league once I tried making any actual gameplay though, as the only thing it has is a player which faces the direction of the mouse, and a green thing which follows the player but does nothing to you."]}),images:[{src:"/articles/devChronicles/images/mainServer/1.png",alt:"Screenshot 1 of MainServer",caption:"The title screen (I was clearly quite the English prodigy at the time)"},{src:"/articles/devChronicles/images/mainServer/2.png",alt:"Screenshot 2 of MainServer",caption:"The only section of map featuring green guy and my entirely white player"}],imageRight:!0}),e.jsx(n,{spacing:"50px"}),e.jsx("p",{className:"subsectionHeading",children:"Interlude 1"}),e.jsx(o,{children:e.jsx("p",{children:"So those were all the notable games from the first group. From what I can surmise from the dates of when these games were created, I had a hiatus from making games under groups and instead opted to make games under my Roblox account instead for a while. From this point onwards is where I really started to take learning Roblox development seriously, as the spike in quality is quite drastic among the next games."})}),e.jsx(n,{spacing:"50px"}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 5 - ",e.jsx("a",{href:"https://www.roblox.com/games/5141342966/Pig-Riding",target:"_blank",children:"Pig Riding! 🐷"})]}),e.jsx(t,{text:e.jsxs("p",{children:[`Now this probably sounds like a very strange game from first impression, and it definitely is. However there was context to it, but I won't really explain it in much detail here. It was essentially a sort of surprise game for a friend of mine, that would later become almost sentimental for me, considering it was the first "big" project I worked on in Roblox (that's going to be bit of a recurring theme actually). There really isn't anything much in this game though, and everything it does have is very rough around the edges.`,e.jsx("br",{}),e.jsx("br",{}),"First of all, the namesake of the game, the whole pig riding thing. At the time I had absolutely no idea how to take in player input and translate that towards the movement of an object, so I had to find an easier way to make the pig rideable. As a result, I made use of the only thing I remembered being rideable in Roblox: a car. The pig in game is literally just an invisible car with a pig model attached to it, and it's so bad. I somehow sucked so bad at making even a default Roblox car that the thing barely even functions. It turns horribly and is super shaky when any movement to the side happens.",e.jsx("br",{}),e.jsx("br",{}),"Secondly, everything else in the game is pretty much pointless. I never developed the game enough for anything to matter. There's mechanics like a super simple quest (I actually forget what it is since I can't do it again), and the only other notable mechanic is how you can mine gold for coins, which again, does nothing because you can't do anything with coins."]}),images:[{src:"/articles/devChronicles/images/pigRiding1/1.png",alt:"Screenshot 1 of Pig Riding! 🐷",caption:"Carrot on a Stick item"},{src:"/articles/devChronicles/images/pigRiding1/2.png",alt:"Screenshot 2 of Pig Riding! 🐷",caption:"Doing the game title"},{src:"/articles/devChronicles/images/pigRiding1/3.png",alt:"Screenshot 3 of Pig Riding! 🐷",caption:"Mining gold ore mechanic (I have no idea why I called it health...)"},{src:"/articles/devChronicles/images/pigRiding1/4.png",alt:"Screenshot 4 of Pig Riding! 🐷",caption:"NPC interaction"},{src:"/articles/devChronicles/images/pigRiding1/5.png",alt:"Screenshot 5 of Pig Riding! 🐷",caption:"Selling gold ore UI"},{src:"/articles/devChronicles/images/pigRiding1/6.png",alt:"Screenshot 6 of Pig Riding! 🐷",caption:"Barn area"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 6 - ",e.jsx("a",{href:"https://www.roblox.com/games/5853591308/pog",target:"_blank",children:"pog"})]}),e.jsx(t,{text:e.jsx("p",{children:`I have no idea what the context was for the name. But this one is super simple and we basically went over it already. It's just a slightly more advanced version of "MainServer", this time with UI and some different graphics. There's nothing to really mention here, I just wanted to show that it existed, so I'll move on.`}),images:[{src:"/articles/devChronicles/images/pog/1.png",alt:"Screenshot 1 of pog",caption:"Save selection screen"},{src:"/articles/devChronicles/images/pog/2.png",alt:"Screenshot 2 of pog",caption:"Main area with the green guy once again"}],imageRight:!0}),e.jsx(n,{spacing:"50px"}),e.jsx("p",{className:"subsectionHeading",children:"Interlude 2"}),e.jsx(o,{children:e.jsxs("p",{children:["And that's really all I worked on of significance under my account. I created my second group, ",e.jsx("a",{href:"https://www.roblox.com/share/g/7387289",target:"_blank",children:"brenman60 Games"}),", August 10th, 2020 (according to old group descriptions). This group would become my main means of Roblox development. It would also become the source of my most impressive Roblox projects, as well as the last of them."]})}),e.jsx(n,{spacing:"50px"}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 7 - ",e.jsx("a",{href:"https://www.roblox.com/games/5572519603/Soul-Crushing-Job-Simulator",target:"_blank",children:"Soul Crushing Job Simulator"})]}),e.jsx(t,{text:e.jsxs("p",{children:[`If I remember correctly, this game was an evolution of sorts of the previous game "Sitting Simulator", and the name of this game was in part a result of that. For being a joke game, it's actually got some spirit to it, with a little tutorial dialogue when you join as well as some extra apps on the computer.`,e.jsx("br",{}),e.jsx("br",{}),"I also distinctly remember working on this game during my online classes I wasn't paying any attention to, so it gets credit for that too.",e.jsx("br",{}),e.jsx("br",{}),"Once again I don't really have anything notable to say about this one. It's the precursor to another game I'll be showing soon, however."]}),images:[{src:"/articles/devChronicles/images/soulCrushingJobSimulator/1.png",alt:"Screenshot 1 of Soul Crushing Job Simulator",caption:"Dialogue after joining the game"},{src:"/articles/devChronicles/images/soulCrushingJobSimulator/2.png",alt:"Screenshot 2 of Soul Crushing Job Simulator",caption:"Main gameplay (which was just you having to copy whatever the text was)"},{src:"/articles/devChronicles/images/soulCrushingJobSimulator/3.png",alt:"Screenshot 3 of Soul Crushing Job Simulator",caption:"UI of the computer desktop"},{src:"/articles/devChronicles/images/soulCrushingJobSimulator/4.png",alt:"Screenshot 4 of Soul Crushing Job Simulator",caption:"Computer logging in UI"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 8 - ",e.jsx("a",{href:"https://www.roblox.com/games/5985816473/Pig-Riding",target:"_blank",children:"Pig Riding"})]}),e.jsx(t,{text:e.jsxs("p",{children:['This is a direct "sequel" to the first "Pig Riding" game I made. I no longer remember really why I wanted to make another one of these, but this one I was planning on being much more ambitious with. Like most of the other projects so far, those plans never came to fruition, and I soon moved onto other projects. However, I hold this game in pretty high regard simply because it taught me some important lessons in programming which I would carry with me much later on.',e.jsx("br",{}),e.jsx("br",{}),"The first of which is that the farm plots in the game save and load, which wasn't something that I just knew how to do. Being inexperienced, I just didn't comprehend the fact that you couldn't just save and load models, and it only dawned on me after tons of trial and error that you instead can save a reference to the model, such as a name or id, and then use that reference to load it back in later. I consider learning this to be a huge milestone for me, as it's an important topic to be knowledgeable about in any programming language, especially in the context of game development.",e.jsx("br",{}),e.jsx("br",{}),"Second, I find that this was when I first became exposed to scope and learned a little about how it can both help and hurt you depending on how it's managed. Like I mentioned, this game's plans were never acted on, but that doesn't mean they weren't well thought out. I recall coming up with various ideas and either building upon certain ones or shooting them down as I recognized whether or not they fit with what I was going for. Knowing which ideas are realistic towards the vision of your game is just as important as how they're implemented."]}),images:[{src:"/articles/devChronicles/images/pigRiding2/8.png",alt:"Screenshot 1 of Pig Riding",caption:"Starter area with the default pig model"},{src:"/articles/devChronicles/images/pigRiding2/2.png",alt:"Screenshot 2 of Pig Riding",caption:"Player farm filled with crops"},{src:"/articles/devChronicles/images/pigRiding2/3.png",alt:"Screenshot 3 of Pig Riding",caption:"Player farm shop"},{src:"/articles/devChronicles/images/pigRiding2/4.png",alt:"Screenshot 4 of Pig Riding",caption:"Unlockable bunny"},{src:"/articles/devChronicles/images/pigRiding2/5.png",alt:"Screenshot 5 of Pig Riding",caption:"Doing the game title"},{src:"/articles/devChronicles/images/pigRiding2/6.png",alt:"Screenshot 6 of Pig Riding",caption:"Factory UI"},{src:"/articles/devChronicles/images/pigRiding2/7.png",alt:"Screenshot 7 of Pig Riding",caption:"Shop UI"},{src:"/articles/devChronicles/images/pigRiding2/1.png",alt:"Screenshot 8 of Pig Riding",caption:"Plant Seed UI"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 9 - ",e.jsx("a",{href:"https://www.roblox.com/games/6340559226/The-Internet-1-1",target:"_blank",children:"The Internet"})]}),e.jsx(t,{text:e.jsxs("p",{children:[`Initially, I started this project as a means to hop on the bandwagon of people creating games in which only one player would be able to claim something, a genre which was popular around the time. If you aren't aware of that trend, I'll use an example to explain it. One of the many games in this genre was one in which there was just a massive field of gravestones, and each one had the name of a player who'd claimed that gravestone previously. The already taken gravestones couldn't be overwritten with someone else's name, they were forever stuck with whoever had claimed it first's name. These types of games allowed you to basically "immortalize" yourself within them, and it felt like a competition to try your best to get a good spot before they were all taken.`,e.jsx("br",{}),e.jsx("br",{}),"The connection I was going to make towards that genre was that this one would be based on websites, that you'd only be able to claim a domain if nobody else had claimed that specific one before, so I'd be a competition to claim the best domains first. I wasn't fast enough to finish the game before that trend had already died down, so it never got popular to any degree.",e.jsx("br",{}),e.jsx("br",{}),'Looking past that trend, the game itself has some big issues to it. As you can probably tell, the base of the game is actually taken from "Soul Crushing Job Simulator", with this game looking to be a sort of successor to it. However, the most glaring issues are within the websites portion of the game. When I launched the game, it had some huge issues regarding websites not saving, which I had to attempt to fix multiple times. As well as that, the website editor is very clunky, with the UI being a mess, and full of small issues that I never got around to fixing.',e.jsx("br",{}),e.jsx("br",{}),"Overall, this game was definitely a challenge to develop and pretty fun at that, yet not really my proudest work."]}),images:[{src:"/articles/devChronicles/images/theInternet/1.png",alt:"Screenshot 1 of The Internet",caption:"Map area"},{src:"/articles/devChronicles/images/theInternet/2.png",alt:"Screenshot 2 of The Internet",caption:"Computer desktop UI"},{src:"/articles/devChronicles/images/theInternet/6.png",alt:"Screenshot 3 of The Internet",caption:"Website navigation UI"},{src:"/articles/devChronicles/images/theInternet/5.png",alt:"Screenshot 4 of The Internet",caption:"Website editor UI"},{src:"/articles/devChronicles/images/theInternet/4.png",alt:"Screenshot 5 of The Internet",caption:"Website search UI"},{src:"/articles/devChronicles/images/theInternet/3.png",alt:"Screenshot 6 of The Internet",caption:"Website UI"}],imageRight:!0}),e.jsxs("p",{className:"subsectionHeading",children:["Chapter 10 - ",e.jsx("a",{href:"https://www.roblox.com/games/6752791668/The-Island-of-Fareo-Discontinued-on-Roblox",target:"_blank",children:"The Island of Fareo"})]}),e.jsx(t,{text:e.jsxs("p",{children:["The Island of Fareo was undeniably the most important Roblox project I worked on, as well as the last. I was incredibly ambitious in what I wanted to create, and unfortunately never got around to executing much of it.",e.jsx("br",{}),e.jsx("br",{}),"Initially, the game started as pretty much a simpler version of the popular game ",e.jsx("a",{href:"https://www.roblox.com/games/35397735/Scuba-Diving-at-Quill-Lake",target:"_blank",children:e.jsx("i",{children:"Scuba Diving at Quill Lake🤿"})}),". A few years prior to starting this project, that game was one of my favorite games on Roblox (and still probably is), and I think I just wanted to create a game with the same sort of feelings of adventure to it.",e.jsx("br",{}),e.jsx("br",{}),"Over the development, the game just kept growing bigger and bigger with new things I wanted to include. I took huge inspirations from ",e.jsx("i",{children:"Subnautica"}),", ",e.jsx("i",{children:"Terraria's Calamity Mod"}),", as well as ",e.jsx("i",{children:"Terraria"})," itself to create some of the biomes and concepts. I had plans for lore to be found in various fragments throughout the map, most of which I unfortunately forget by now. Many of the character names were also anagrams of other names, usually things from Lord of The Rings (since I was really into it at the time). I thought it was a great idea back then: it was not.",e.jsx("br",{}),e.jsx("br",{}),"Looking back at it, I actually find many aspects of the game very charming and fun. I think that if I had finished it, this game probably could've gotten somewhat popular, but probably not anywhere near the popularity of its inspiration. It was around this point which I began seriously thinking of what I really wanted out of developing on Roblox and what it could realistically provide me.",e.jsx("br",{}),e.jsx("br",{}),"This game had one of the biggest long lasting effects on me personally though, with it inspiring many other ideas for projects further on. Overall, I found the time I worked on this game to be up there as some of the most enjoyable time that I've spent developing something, and for that I consider this to be one of my favorite projects to date."]}),images:[{src:"/articles/devChronicles/images/theIslandOfFareo/1.png",alt:"Screenshot 1 of The Island of Fareo",caption:"Main spawn and shopkeeping area"},{src:"/articles/devChronicles/images/theIslandOfFareo/2.png",alt:"Screenshot 2 of The Island of Fareo",caption:"Biome which was heavily inspired by the Sunken Sea from Terraria's Calamity Mod"},{src:"/articles/devChronicles/images/theIslandOfFareo/3.png",alt:"Screenshot 3 of The Island of Fareo",caption:"Angler fish enemy biting my leg"},{src:"/articles/devChronicles/images/theIslandOfFareo/4.png",alt:"Screenshot 4 of The Island of Fareo",caption:"The shopkeeper you buy corruption related items from"},{src:"/articles/devChronicles/images/theIslandOfFareo/5.png",alt:"Screenshot 5 of The Island of Fareo",caption:"Navigating the water with a dinghy"},{src:"/articles/devChronicles/images/theIslandOfFareo/6.png",alt:"Screenshot 6 of The Island of Fareo",caption:"The shopkeeper you sell found artifacts to"},{src:"/articles/devChronicles/images/theIslandOfFareo/7.png",alt:"Screenshot 7 of The Island of Fareo",caption:"The UI for unlocked artifacts you find throughout the world"},{src:"/articles/devChronicles/images/theIslandOfFareo/8.png",alt:"Screenshot 8 of The Island of Fareo",caption:"The shopkeeper you buy upgrades and tools from"}],imageRight:!0}),e.jsx(n,{spacing:"150px"}),e.jsx("p",{className:"sectionHeading",children:"The Unity Arc"}),e.jsx(o,{children:e.jsxs("p",{children:['I began learning Unity in August 2021 (very beginning of my 8th grade year of middle school), as a result of growing concerns regarding Roblox development. My move to Unity had actually been planned out for a short time before I actually started learning it, as I had wanted to finish my last Roblox game, "The Island of Fareo" before completely moving on. Evidently, I found learning Unity to be much more entertaining than the slow moving work on Roblox, and so I made the full jump earlier than I planned.',e.jsx("br",{}),e.jsx("br",{}),"I chose to move onto Unity because, at the time, it's pretty much all I knew of. The YouTuber, ",e.jsx("a",{href:"https://www.youtube.com/@Danidev",target:"_blank",children:e.jsx("i",{children:"Dani"})}),", was becoming very popular at the time, and because he used Unity, it seemed like the best option to me. That's really all there was to it.",e.jsx("br",{}),e.jsx("br",{}),"Anyway, I've got quite a couple fairly impressive projects from the past few years that I'd like to show. It's going to be pretty hard to chronicle these in any specific order though, since they're not as organized as the Roblox games were."]})}),e.jsx("p",{className:"subsectionHeading",children:"Installment 1 - Tank Wars"}),e.jsx(t,{text:e.jsxs("p",{children:["I believe this was technically the second project I ever worked on in Unity, however I'm mentioning it first as it was the simpler of the two. The main inspiration for this was ",e.jsx("a",{href:"https://www.coolmathgames.com/0-awesome-tanks-2",target:"_blank",children:e.jsx("i",{children:"Awesome Tanks 2"})})," from Coolmath Games. As you'll see later, this project served as the predecessor to something much much bigger."]}),images:[{src:"/articles/devChronicles/images/tankWars/1.png",alt:"Screenshot 1 of Tank Wars",caption:"Player spawn area with breakable crates"},{src:"/articles/devChronicles/images/tankWars/2.png",alt:"Screenshot 2 of Tank Wars",caption:"Player being shot at by purple enemy tank"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"Installment 2 - Galaxy Sprint"}),e.jsx(t,{text:e.jsxs("p",{children:["Galaxy Sprint actually began as a total joke game, intended to blatantly copy the ",e.jsx("a",{href:"https://cdn.i-ready.com/instruction/reward-games/master/49/game-lanerunner/",target:"_blank",children:"i-Ready game of the same name"}),". I vehemently hated i-Ready in middle school, since we were forced to use it in 7th and 8th grade. I figured that I could copy one of the games they made you play during their knowledge check things, and host it on a website so that my friends and I could play it in class. However, after those friends in school took a larger interest in the game than I thought they would, I spent much of my 8th grade year adding more and more content.",e.jsx("br",{}),e.jsx("br",{}),"This was the first big project I started in Unity, so the code was super messy and crude (and much of it still is). Not to mention how - in fear of the school year ending before I could finish content for my friends - I worked as fast as I could on new features on the weekends after school weeks, resulting in very rushed code and features.",e.jsx("br",{}),e.jsx("br",{}),"I believe near the end of middle school I was able to give the game mobile controls and put it up on the Google Play Store. I think that was probably why I decided to work on and maintain the game for so long even after middle school had ended.",e.jsx("br",{}),e.jsx("br",{}),"As I learned more and got better at programming throughout the years, the game became harder to maintain because of just how atrocious the old code is. I've done some revisions to the code over time yet most has remained terrible for a couple reasons.",e.jsx("br",{}),e.jsx("br",{}),"First, I've considered reworking the gameplay loop of the game, considering it's quite boring as is. However, after sifting through various ideas for reworks time and time again I've found that to create an actually fun gameplay loop, there'd have to be some huge changes. This always had led me to just opting to essentially remake the game entirely, which of course would probably make more sense to just entirely remake it rather than work through years of old code rewriting it all.",e.jsx("br",{}),e.jsx("br",{}),"Second, I then also keep catching myself in a crossroads of deciding if this new game would be just a rework, or an entirely new game, like a sequel of sorts. All this to say that going back and rewriting that old code always ends up feeling quite pointless to me, so I haven't gotten around to doing it.",e.jsx("br",{}),e.jsx("br",{}),"I have really no clue if I truly want to remake this game or anything. Recently, I've had some promising ideas for what that sequel game could be, but I've struggled getting any of those ideas set in stone so I suppose we will see."]}),images:[{src:"/articles/devChronicles/images/galaxySprint/2.png",alt:"Screenshot 2 of Galaxy Sprint",caption:"Main Menu UI"},{src:"/articles/devChronicles/images/galaxySprint/3.png",alt:"Screenshot 3 of Galaxy Sprint",caption:"First map level selection"},{src:"/articles/devChronicles/images/galaxySprint/4.png",alt:"Screenshot 4 of Galaxy Sprint",caption:"Trail shop UI"},{src:"/articles/devChronicles/images/galaxySprint/5.png",alt:"Screenshot 5 of Galaxy Sprint",caption:"Main gameplay"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"Installment 3 - Darkening"}),e.jsx(t,{text:e.jsxs("p",{children:[`Right before the beginning of my Sophomore year of high school, me and a friend had been "challenging" each other to make small games within the span of a few days each, and we'd have our other friends judge who made the better game. Darkening was the result of one of those events. At first I believe it simply started as a question of who could make the better horror game, and then quickly morphed into who could make the better horror game, but specifically one with mechanics inspired by Five Nights at Freddy's (or it just so happened that we both used Five Nights at Freddy's as inspiration). The challenge went on for just about six days I believe.`,e.jsx("br",{}),e.jsx("br",{}),"My friend ended up creating ",e.jsx("a",{href:"https://www.roblox.com/games/14390277553/Five-Nights-at-Jerrys",target:"_blank",children:e.jsx("i",{children:"Five Nights at Jerry's"})}),". Although it doesn't really innovate on mechanics, it's actually a super impressive game, especially considering the time constraints we had.",e.jsx("br",{}),e.jsx("br",{}),"I think for smaller projects like these, my favorite parts are always building up the ambience in the game. Hyperfocusing on small details such as audio is always so rewarding because of the impact it has on players.",e.jsx("br",{}),e.jsx("br",{}),'Unfortunately the game suffers from a lack of playtesting due to the small development window, so the release version had tons of bugs that impacted gameplay pretty significantly. I went back at times to fix some bugs here and there, but at the same time the game design is somewhat irreparable in some aspects so what I would typically consider "bugs" are kind of baked into the game.',e.jsx("br",{}),e.jsx("br",{}),"Just like Galaxy Sprint, this is another game which I'd come up with numerous ideas for reworks but never followed through on any. Although in writing this and remembering some of the rework ideas I had come up with, I think this is probably the game with the most potential for me to update in the future."]}),images:[{src:"/articles/devChronicles/images/darkening/1.png",alt:"Screenshot 1 of Darkening",caption:"Camera system displaying Camera 7"},{src:"/articles/devChronicles/images/darkening/2.png",alt:"Screenshot 2 of Darkening",caption:"Peering out the door of the bedroom"},{src:"/articles/devChronicles/images/darkening/3.png",alt:"Screenshot 3 of Darkening",caption:"Camera system displaying Camera 1"},{src:"/articles/devChronicles/images/darkening/4.png",alt:"Screenshot 4 of Darkening",caption:"Camera system displaying Camera 2"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"Installment 4 - Forlorn"}),e.jsx(t,{text:e.jsxs("p",{children:[`At the beginning of my Junior year of high school, my Info Tech class was assigned a "group game project" in which we had to partner up with one other person, plan out tasks, then create both a game and a website to advertise that game. I believe we had around ~2 months or so to get everything done. The theme for our year's games was "immigration".`,e.jsx("br",{}),e.jsx("br",{}),"A majority of people in my class were less than thrilled for this project, you could say, but I was incredibly excited. I'd been in Info Tech classes for Freshmen and Sophomore year too but we'd never gotten to do anything like this, so I really wanted to make something good for it.",e.jsx("br",{}),e.jsx("br",{}),"At the time of starting the project, I had been playing a ton of ",e.jsx("i",{children:"Risk of Rain 2"}),", and so I was really wanting to make some sort of rougelike game. Surprisingly, ",e.jsx("i",{children:"Risk of Rain 2"}),` doesn't exactly mesh well with the theme we were given, so I had to improvise if I wanted it to work. I instead opted for the idea that you'd play as an immigrant moving through parts of a city (equivalent of RoR2's environments), and pick up items along the way that'd slowly increase your "power". The items part didn't really work out, and was instead replaced with status effects and a skill tree.`,e.jsx("br",{}),e.jsx("br",{}),"This was actually a game that I never really got the drive to go back and expand, so as you see it (at least as of writing this), is how I finished it for that project. Despite this being a school project and all, I'm actually very proud of how it came out and I would go as to say it's among my best projects.",e.jsx("br",{}),e.jsx("br",{}),"Of course, that's not to say it doesn't have its flaws though. The gameplay gets quite tedious and boring and there's not very much depth to it. However I think overall everything else about the game makes up for that in my opinion. So far this is probably my favorite game I've completed, since I think I really did well on the artstyle and overall feel of the game."]}),images:[{src:"/articles/devChronicles/images/forlorn/1.png",alt:"Screenshot 1 of Forlorn",caption:"Intro cutscene dialogue"},{src:"/articles/devChronicles/images/forlorn/2.png",alt:"Screenshot 2 of Forlorn",caption:"Entering pizza shop building"},{src:"/articles/devChronicles/images/forlorn/3.png",alt:"Screenshot 3 of Forlorn",caption:"Skill tree UI"},{src:"/articles/devChronicles/images/forlorn/4.png",alt:"Screenshot 4 of Forlorn",caption:"Job management UI"},{src:"/articles/devChronicles/images/forlorn/5.png",alt:"Screenshot 5 of Forlorn",caption:"Cops safety event"},{src:"/articles/devChronicles/images/forlorn/6.png",alt:"Screenshot 6 of Forlorn",caption:"Snowstorm safety event"}],imageRight:!0}),e.jsx("p",{className:"subsectionHeading",children:"Installment 5 - Tank Strike"}),e.jsx(o,{children:e.jsxs("p",{children:["Now despite Tank Strike being undeniably my biggest project ever, I'm going to keep this somewhat brief, only because so far all these projects have been things which have seen an end at some point, and Tank Strike is still in active development.",e.jsx("br",{}),e.jsx("br",{}),`I've been working on this game on and off pretty much ever since I started "Tank Wars", and development has also been very up and down throughout that time.`,e.jsx("br",{}),e.jsx("br",{}),"Unfortunately recently I haven't had the time nor inspiration to get as much progress done as I used to, but things are still going fairly smoothly with development. I've been taking a few steps back at times to look at exactly how I want this game to turn out and what needs to be added, removed, or changed in order to make that happen.",e.jsx("br",{}),e.jsx("br",{}),"Having started Tank Strike during the very beginning of my Unity learning, I think it's definitely taken a hit from inexperience, as well as scope creep. All in all, I'm hoping that with my new vision for the game and what I want out of it, I can hopefully sort of streamline the development and get the game finished sometime in the nearish future."]})}),e.jsx(n,{spacing:"150px"}),e.jsx("p",{className:"sectionHeading",children:"Conclusion"}),e.jsx(o,{children:e.jsx("p",{children:"And that's basically everything major I've worked on throughout the years. Of course there's numerous other projects that either were too insignificant or just not related enough to game development to make the cut. This article has also gotten quite long by now as well, so I figured anything else might be a bit too much. Anyways, I don't have really any closing words, so thank you for reading. I hope to be able to make more of this type of thing in the future."})})]})]})}export{d as default};
